import './ExpenseForm.css'
import React, {useState} from 'react';

const ExpenseForm = () => {
    const [title, setTitle] = useState('');
    const [date, setDate] = useState('');
    const [price, setPrice] = useState('');

    const submitHandler = () => {

    }
    const titleChangeHandler = (event) => {
        setTitle(event.target.value);
    }
    const dateChangeHandler = (event) => {
        setDate(event.target.value);
    }
    const priceChangeHandler = (event) => {
        setPrice(event.target.value);
    }
    return (
        <form onSubmit = {submitHandler}>
            <div className = 'new-expense__controls'>
                <div className = 'new-expense__control'>
                    <label htmlFor = 'newExpenseTitle'>New Expense</label>
                    <input type = 'text' id = 'newExpenseTitle' onChange = {titleChangeHandler}></input>
                </div>
                <div className = 'new-expense__control'>
                    <label htmlFor = 'newExpenseItemDate'>New Expense Date</label>
                    <input type = 'date' min = "2020-01-01" max = '2022-12-31' id = 'newExpenseItemDate' onChange = {dateChangeHandler} ></input>
                </div>
                <div className = 'new-expense__control'>
                    <label htmlFor = 'newExpenseItemPrice'>New Expense Price</label>
                    <input type = 'number' min = "1" step = "1" id = 'newExpenseItemsPrice' value = "2" onChange = {priceChangeHandler}></input>
                </div>
                <div className = 'new-expense__actions'>
                    <button type = 'submit'>Add Expense</button>
                </div>
            </div>
        </form>
    )
}
export default ExpenseForm;
